import type { LocalizedTutorialContent } from '../tutorials-longform-i18n';

// Localized long-form content for one tutorial. Generated from validated
// per-locale translation JSONs; en renders from the Markdown source.
export const entry: Partial<Record<string, LocalizedTutorialContent>> = {
  "zh": {
    title: "Open Design——把你手头已有的 Agent 变成一台设计引擎",
    summary: "一份聚焦 Open Design 中大多数教程都跳过的部分的实用指南——如何选择并切换它背后的模型。你的编程 agent 是引擎，你把它指向的模型则是质量旋钮。安装它、接上 Gemini CLI 或 Claude，并学会让模型与任务相匹配。基于 Codedigipt 的实操演示。",
    bodyHtml: "<p>本指南聚焦于大多数演示都一带而过的部分：<strong>引擎</strong>。Open Design 本身只是设计界面——真正的生成由你所指向的编程 agent 和模型完成，而这个选择正是决定输出质量的最大杠杆。本文沿用 <strong>Codedigipt</strong> 在<a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">他的实操演示</a>中使用的配置，并按当前版本重写、更新。想看实时运行请观看上方视频，或继续阅读文字版。</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/workspace-home.webp\" alt=\"Open Design 工作区——描述你想要的内容并选择一种模式。\">\n<em>Open Design 工作区：描述你想构建的东西，选择一种模式，剩下的交给你的智能体完成。</em></p>\n<h2 id=\"what-is-open-design\">什么是 Open Design？</h2>\n<p>Open Design 是一个开源、本地优先的设计平台，<strong>运行在你已经在用的编程 agent 之上</strong>。它不自带模型——而是扫描你机器上已有的各种 CLI（Claude Code、Codex、Cursor、Gemini、Copilot、OpenCode，以及另外几十种），并把那个 agent 当作设计引擎。所以工作跑在你已有的订阅或免费额度上，而不是再添一笔设计账单。</p>\n<ul>\n<li><strong>开源，Apache-2.0</strong>——克隆它、自托管它、逐行阅读它。</li>\n<li><strong>本地运行</strong>——你的项目就是你自己机器上的文件夹。</li>\n<li><strong>自带引擎</strong>——任何受支持的 CLI，或你自己的 API 密钥。</li>\n<li><strong>内置一座深厚的设计系统与技能库</strong>，让你不必从空白画布开始。</li>\n<li><strong>不止于原型</strong>——原型、幻灯片、图像生成和视频。</li>\n</ul>\n<h2 id=\"the-key-idea-the-model-is-the-quality-knob\">核心理念：模型就是质量旋钮</h2>\n<p>这是 Codedigipt 最终得出的心智模型，也是最值得内化的一点：<strong>Open Design 的输出质量与你所选的模型同步。</strong>Open Design 提供结构——技能、设计系统、探索流程——但真正的设计判断来自引擎。用一个又快又便宜的模型，你得到的是又快又便宜的草稿；用一个顶级模型，同样的提示词和设计系统会带来精致得多的结果。</p>\n<p>这是特性，不是局限。它意味着你可以为每个项目在成本与质量之间调节，并随时切换引擎。</p>\n<h2 id=\"step-1--install-open-design\">第 1 步——安装 Open Design</h2>\n<p>三种入门方式：</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>方式</th><th>适合</th><th>前置要求</th></tr></thead><tbody><tr><td><strong>桌面应用</strong></td><td>大多数人——零配置</td><td>无。下载并打开即可。</td></tr><tr><td><strong>从源码运行</strong></td><td>想阅读或修改代码的开发者</td><td>Node <code>~24</code>、pnpm <code>10.33.x</code></td></tr><tr><td><strong>装进你的 agent</strong></td><td>长居终端的人</td><td>一个已有的编程 agent CLI</td></tr></tbody></table>\n<p>最快的方式是从 <a href=\"https://open-design.ai/download\">open-design.ai/download</a> 下载<strong>桌面应用</strong>——它会自动检测你已安装的 agent CLI。要从源码运行（Codedigipt 走的这条路）：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>打开它打印出的本地 URL——它解析出的是一个动态端口，所以不要写死。Codedigipt 凭经验提醒的一个坑：你需要 <strong>Node 24</strong>。在 Node 22 上它对他无法启动；请先安装 Node 24 LTS。Corepack 会选定固定版本的 pnpm。</p>\n<h2 id=\"step-2--choose-your-engine\">第 2 步——选择你的引擎</h2>\n<p>这是最关键的一步。打开设置（配置执行模式），从 Open Design 在你机器上检测到的 CLI 中，挑选将驱动生成的那个 agent。任何未安装的都会显示为不可用。</p>\n<ul>\n<li><strong>Gemini CLI</strong>——Codedigipt 在设计阶段的首选：设计直觉强，免费额度也很经用。生成就跑在这些额度上。</li>\n<li><strong>Claude Code</strong>——把它指向一个擅长设计的模型（Sonnet 或 Opus），获得最高保真度的输出。</li>\n<li><strong>OpenCode</strong>——自带能干的默认模型（例如 MiniMax、GLM），适合不想配置任何东西的你。</li>\n<li><strong>Anthropic API（BYOK）</strong>——没有 CLI？填入一个 API 密钥，直接选择模型。这让你能用上 Claude 级别的输出，<strong>而无需单独的 Claude Design 订阅</strong>——你出密钥，Open Design 出设计界面。</li>\n</ul>\n<h2 id=\"step-3--generate-then-judge-by-engine\">第 3 步——先生成，再按引擎来评判</h2>\n<p>创建一个项目，给它起名，选择<strong>高保真</strong>，写下你的需求说明（Codedigipt 为一个「auth-as-a-service」API 构建落地页）。在动笔之前，Open Design 会返回一份简短的<strong>探索表单</strong>——输出格式、主界面、受众、视觉调性、品牌方向——让 agent 锁定正确方向，而不是靠猜。填好它，挑一个视觉方向，它就开始构建。</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/generated-prototype.webp\" alt=\"在 Open Design 中生成的真实原型。\">\n<em>在预览中呈现的真实生成原型——一个深色、富有电影感的代理公司落地页。</em></p>\n<p>在快速模型上的结果（Codedigipt 用的是一个 Gemini flash 预览版）是几秒钟内一份干净、可用的初稿。他反复强调的实诚提醒：<strong>你得到的输出，取决于你所选模型的水平。</strong>想要 Opus 级别的精致？把引擎切到 Claude 的 Opus 上，对同一份需求重新运行——同样的技能、同样的设计系统，结果更锐利。</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/plugin-library.webp\" alt=\"Open Design 的插件库，包含可安装的技能。\">\n<em>插件库：直接从注册表安装技能——包括反粗制滥造（anti-slop）的设计技能。</em></p>\n<p>满意之后，<strong>分享</strong>菜单可导出为 PDF、PPTX、独立 HTML 或 ZIP——或直接部署到 Vercel。你可以在 <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> 浏览完整的插件库。</p>\n<h2 id=\"tips\">小贴士</h2>\n<ul>\n<li><strong>让模型与任务相匹配。</strong>快速草稿和迭代用便宜/快的模型；面向客户的最终成稿用顶级模型。</li>\n<li><strong>使用本地 CLI</strong>，这样生成就跑在你已有的订阅或免费额度上。</li>\n<li><strong>用 BYOK 获得 Claude 级别质量，而无需 Claude Design 套餐</strong>——把一个 Anthropic 密钥填进设置并选择模型。</li>\n<li><strong>别拿弱模型来怪工具。</strong>再好的设计系统也救不了一个弱引擎；如果输出显得单薄，先升级模型，再去改提示词。</li>\n<li><strong>把探索表单填完整</strong>——这正是引擎一次就锁定方向的方式。</li>\n</ul>\n<h2 id=\"faq\">常见问题</h2>\n<p><strong>我选的模型真的会让输出差那么多吗？</strong>\n是的——这是最大的杠杆。Open Design 提供技能和设计系统，但设计判断来自引擎。同一份需求在 Opus 与一个快速预览模型上跑，精致度有明显差别。</p>\n<p><strong>我能不为 Claude Design 付费就用上 Claude 级别的质量吗？</strong>\n可以。把 Open Design 指向 Claude Code，或把一个 Anthropic API 密钥填进设置（BYOK）并选择模型。你无需单独的 Claude Design 订阅就能获得这样的输出。</p>\n<p><strong>我能在项目中途切换模型吗？</strong>\n可以——在设置里更换 agent/模型并重新运行。同样的技能和设计系统，背后换了一台引擎。</p>\n<p><strong>它免费吗？</strong>\n应用本身在 Apache-2.0 下开源，本地运行免费。你只需为所连接 agent 的模型/额度付费。</p>\n<hr>\n<p><em>本文字版指南基于 Codedigipt 的实操演示。请观看上方完整视频，并<a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">订阅 Codedigipt</a>，获取更多实用的 AI 工具配置。</em></p>",
  },
  "ja": {
    title: "Open Design — すでに持っているエージェントをデザインエンジンに変える",
    summary: "Open Design のなかで、ほとんどのチュートリアルが飛ばす部分——背後のモデルを選び、入れ替えること——に絞った実践ガイド。あなたのコーディングエージェントがエンジンであり、そこに向けるモデルが品質のつまみです。インストールし、Gemini CLI または Claude をつなぎ、モデルを仕事に合わせる方法を学びましょう。Codedigipt の実演に基づきます。",
    bodyHtml: "<p>本ガイドは、ほとんどの解説がさらりと流す部分、すなわち<strong>エンジン</strong>に焦点を当てます。Open Design 自体はデザインの場にすぎず、実際の生成はあなたが向けたコーディングエージェントとモデルが行います。そしてその選択こそ、出力品質を左右する最大のレバーです。本稿は <strong>Codedigipt</strong> が<a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">実演</a>で使っている構成にならい、現行リリースに合わせて書き直し・更新したものです。実際の動きは上の動画で、文章版は以下でご覧ください。</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/workspace-home.webp\" alt=\"Open Design のワークスペース——作りたいものを記述し、モードを選びます。\">\n<em>Open Design のワークスペース：作りたいものを記述し、モードを選べば、あとはエージェントが仕上げます。</em></p>\n<h2 id=\"what-is-open-design\">Open Design とは？</h2>\n<p>Open Design は、<strong>あなたがすでに使っているコーディングエージェントの上で動く</strong>、オープンソースかつローカルファーストのデザインプラットフォームです。独自のモデルは積んでおらず、マシン上にすでにある CLI（Claude Code、Codex、Cursor、Gemini、Copilot、OpenCode、ほか数十種）をスキャンし、そのエージェントをデザインエンジンとして使います。だから作業は、すでに持っているサブスクや無料クレジットで動き、デザイン用の二重請求は発生しません。</p>\n<ul>\n<li><strong>オープンソース、Apache-2.0</strong> — クローンし、セルフホストし、すべての行を読めます。</li>\n<li><strong>ローカルで動作</strong> — プロジェクトは自分のマシン上のフォルダーです。</li>\n<li><strong>エンジンは持ち込み</strong> — 対応するどの CLI でも、あるいは自分の API キーでも。</li>\n<li><strong>デザインシステムとスキルの厚いライブラリ</strong>を内蔵し、白紙のキャンバスから始めずに済みます。</li>\n<li><strong>プロトタイプにとどまらない</strong> — プロトタイプ、スライド、画像生成、そして動画。</li>\n</ul>\n<h2 id=\"the-key-idea-the-model-is-the-quality-knob\">核心となる考え：モデルこそが品質のつまみ</h2>\n<p>これが Codedigipt がたどり着いたメンタルモデルであり、最も身につける価値のある一点です。<strong>Open Design の出力品質は、選んだモデルに追随する。</strong>Open Design は構造——スキル、デザインシステム、ディスカバリーの流れ——を提供しますが、実際のデザイン判断はエンジンから生まれます。速くて安いモデルで動かせば速くて安い下書きが、トップティアのモデルで動かせば、同じプロンプトとデザインシステムからはるかに洗練された結果が得られます。</p>\n<p>これは制約ではなく機能です。プロジェクトごとにコストと品質を天秤にかけて調整でき、いつでもエンジンを入れ替えられるということです。</p>\n<h2 id=\"step-1--install-open-design\">ステップ 1 — Open Design をインストールする</h2>\n<p>入り口は三つ：</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>方法</th><th>向いている人</th><th>必要なもの</th></tr></thead><tbody><tr><td><strong>デスクトップアプリ</strong></td><td>ほとんどの人 — 設定不要</td><td>なし。ダウンロードして開くだけ。</td></tr><tr><td><strong>ソースから実行</strong></td><td>コードを読みたい・改変したい開発者</td><td>Node <code>~24</code>、pnpm <code>10.33.x</code></td></tr><tr><td><strong>自分のエージェントに組み込む</strong></td><td>ターミナルで暮らす人</td><td>既存のコーディングエージェント CLI</td></tr></tbody></table>\n<p>最速の入り口は <a href=\"https://open-design.ai/download\">open-design.ai/download</a> からの<strong>デスクトップアプリ</strong>です — インストール済みのエージェント CLI を自動検出します。ソースから実行する場合（Codedigipt のやり方）：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>表示されたローカル URL を開きます — 動的なポートを解決するので、ハードコードしないでください。Codedigipt が経験から指摘する落とし穴：<strong>Node 24</strong> が必要です。Node 22 では彼の環境で起動しませんでした。先に Node 24 LTS を入れてください。Corepack が固定された pnpm のバージョンを選びます。</p>\n<h2 id=\"step-2--choose-your-engine\">ステップ 2 — エンジンを選ぶ</h2>\n<p>ここが肝心なステップです。設定（実行モードの構成）を開き、Open Design がマシン上で検出した CLI のなかから、生成を駆動するエージェントを選びます。インストールされていないものは無効として表示されます。</p>\n<ul>\n<li><strong>Gemini CLI</strong> — デザイン段階での Codedigipt の一押し：デザイン勘が鋭く、無料枠のクレジットも長持ちします。生成はそのクレジットで走ります。</li>\n<li><strong>Claude Code</strong> — デザインに強いモデル（Sonnet または Opus）に向ければ、最高の忠実度の出力が得られます。</li>\n<li><strong>OpenCode</strong> — 有能なデフォルトモデル（例：MiniMax、GLM）を標準装備。何も設定したくない人向けです。</li>\n<li><strong>Anthropic API（BYOK）</strong> — CLI がない？API キーを入れてモデルを直接選ぶだけ。これにより、<strong>別途 Claude Design のサブスクなしで</strong> Claude 品質の出力が使えます — あなたがキーを、Open Design がデザインの場を持ち込みます。</li>\n</ul>\n<h2 id=\"step-3--generate-then-judge-by-engine\">ステップ 3 — まず生成し、エンジンで判断する</h2>\n<p>プロジェクトを作り、名前を付け、<strong>高忠実度</strong>を選んで、要件を書きます（Codedigipt は「auth-as-a-service」API のランディングページを作ります）。何かを書き出す前に、Open Design は短い<strong>ディスカバリーフォーム</strong>——出力形式、主たる画面、想定読者、ビジュアルのトーン、ブランドの方向性——を返し、エージェントが推測ではなく正しい方向を固定できるようにします。それに答え、ビジュアルの方向を選べば、構築が始まります。</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/generated-prototype.webp\" alt=\"Open Design で生成された実際のプロトタイプ。\">\n<em>プレビューに表示された実際の生成プロトタイプ——ダークで映画的なエージェンシーのランディングページ。</em></p>\n<p>速いモデルでの結果（Codedigipt は Gemini flash プレビューを使用）は、数秒でできる、きれいで使える初稿です。彼が繰り返す正直な但し書き：<strong>出力は、選んだモデルの水準で返ってくる。</strong>Opus 級の洗練が欲しい？エンジンを Opus 上の Claude に切り替え、同じ要件で再実行を——同じスキル、同じデザインシステムで、より鋭い結果に。</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/plugin-library.webp\" alt=\"Open Design のプラグインライブラリ。インストール可能なスキルを備えています。\">\n<em>プラグインライブラリ：レジストリから直接スキルをインストールできます——anti-slop なデザインスキルも含みます。</em></p>\n<p>満足したら、<strong>共有</strong>メニューから PDF、PPTX、単体の HTML、または ZIP に書き出せます——あるいは Vercel へ直接デプロイも。プラグインライブラリの全体は <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> で見られます。</p>\n<h2 id=\"tips\">ヒント</h2>\n<ul>\n<li><strong>モデルを仕事に合わせる。</strong>素早い下書きや反復には安くて速いモデルを、クライアント向けの最終稿にはトップティアのモデルを。</li>\n<li><strong>ローカル CLI を使う</strong>と、生成がすでに持っているサブスクや無料クレジットで走ります。</li>\n<li><strong>Claude Design プランなしで Claude 品質を得るには BYOK</strong> — Anthropic キーを設定に入れ、モデルを選びます。</li>\n<li><strong>弱いモデルの責任を道具に転嫁しない。</strong>良いデザインシステムも弱いエンジンは救えません。出力が薄く見えたら、プロンプトを書き直す前にモデルをアップグレードを。</li>\n<li><strong>ディスカバリーフォームは余さず答える</strong> — それがエンジンを一発で方向づけるやり方です。</li>\n</ul>\n<h2 id=\"faq\">よくある質問</h2>\n<p><strong>選ぶモデルで、出力はそんなに変わるのですか？</strong>\nはい——それが最大のレバーです。Open Design はスキルとデザインシステムを提供しますが、デザイン判断はエンジンから生まれます。同じ要件でも、Opus と速いプレビューモデルとでは、洗練度に目に見える差が出ます。</p>\n<p><strong>Claude Design に課金せず、Claude 級の品質を使えますか？</strong>\nはい。Open Design を Claude Code に向けるか、Anthropic の API キーを設定に入れ（BYOK）、モデルを選びます。別途 Claude Design のサブスクなしで、その出力が得られます。</p>\n<p><strong>プロジェクトの途中でモデルを切り替えられますか？</strong>\nはい——設定でエージェント／モデルを変えて再実行するだけ。同じスキルとデザインシステムで、背後のエンジンだけが変わります。</p>\n<p><strong>無料ですか？</strong>\nアプリは Apache-2.0 のもとオープンソースで、ローカル実行は無料です。料金がかかるのは、接続したエージェントのモデル／クレジットの分だけです。</p>\n<hr>\n<p><em>この文章版ガイドは Codedigipt の実演に基づいています。上の動画を最後までご覧いただき、実用的な AI ツールの構成をもっと知りたい方は <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">Codedigipt をチャンネル登録</a>してください。</em></p>",
  },
  "ko": {
    title: "Open Design — 이미 가진 에이전트를 디자인 엔진으로 바꾸기",
    summary: "대부분의 튜토리얼이 건너뛰는 Open Design의 핵심—뒤에서 돌아가는 모델을 고르고 바꾸는 일—에 집중한 실전 가이드입니다. 코딩 에이전트가 엔진이고, 그 에이전트가 가리키는 모델이 품질 노브입니다. 설치하고, Gemini CLI나 Claude를 연결한 뒤, 작업에 맞춰 모델을 고르는 법을 익혀 보세요. Codedigipt의 실습 워크스루를 바탕으로 합니다.",
    bodyHtml: "<p>이 가이드는 대부분의 워크스루가 슬쩍 넘기는 부분, 즉 <strong>엔진</strong>에 초점을 맞춥니다. Open Design 자체는 디자인 표면일 뿐이고, 실제 생성은 여러분이 가리킨 코딩 에이전트와 모델이 수행합니다. 그리고 그 선택이야말로 결과물 품질을 좌우하는 가장 큰 지렛대입니다. 이 글은 <strong>Codedigipt</strong>가 <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">실습 워크스루</a>에서 사용하는 구성을 따르되, 현재 릴리스에 맞게 다시 쓰고 업데이트한 것입니다. 실제 실행은 위 영상으로, 글 버전은 아래에서 보세요.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/workspace-home.webp\" alt=\"Open Design 워크스페이스 — 원하는 것을 설명하고 모드를 선택하세요.\">\n<em>Open Design 워크스페이스: 만들고 싶은 것을 설명하고 모드를 선택하면 나머지는 에이전트가 처리합니다.</em></p>\n<h2 id=\"what-is-open-design\">Open Design이란?</h2>\n<p>Open Design은 <strong>이미 쓰고 있는 코딩 에이전트 위에서 돌아가는</strong> 오픈소스이자 로컬 우선 디자인 플랫폼입니다. 자체 모델을 싣지 않고, 머신에 이미 있는 CLI(Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode, 그 외 수십 가지)를 스캔해 그 에이전트를 디자인 엔진으로 사용합니다. 그래서 작업은 이미 가진 구독이나 무료 크레딧으로 돌아가며, 디자인용 두 번째 청구서가 생기지 않습니다.</p>\n<ul>\n<li><strong>오픈소스, Apache-2.0</strong> — 클론하고, 셀프호스팅하고, 모든 줄을 읽을 수 있습니다.</li>\n<li><strong>로컬 실행</strong> — 프로젝트는 여러분 자신의 머신에 있는 폴더입니다.</li>\n<li><strong>엔진은 직접 가져오기</strong> — 지원되는 어떤 CLI든, 또는 여러분의 API 키든.</li>\n<li><strong>디자인 시스템과 스킬의 두툼한 라이브러리</strong>가 내장되어, 빈 캔버스에서 시작하지 않아도 됩니다.</li>\n<li><strong>프로토타입을 넘어서</strong> — 프로토타입, 슬라이드, 이미지 생성, 그리고 영상.</li>\n</ul>\n<h2 id=\"the-key-idea-the-model-is-the-quality-knob\">핵심 아이디어: 모델이 곧 품질 노브</h2>\n<p>이것이 Codedigipt가 도달한 멘탈 모델이며, 가장 내면화할 가치가 있는 한 가지입니다. <strong>Open Design의 결과물 품질은 여러분이 고른 모델을 따라간다.</strong> Open Design은 구조—스킬, 디자인 시스템, 디스커버리 흐름—를 제공하지만, 실제 디자인 판단은 엔진에서 나옵니다. 빠르고 저렴한 모델로 돌리면 빠르고 저렴한 초안이 나오고, 최상급 모델로 돌리면 같은 프롬프트와 디자인 시스템에서 훨씬 다듬어진 결과가 나옵니다.</p>\n<p>이것은 한계가 아니라 기능입니다. 프로젝트마다 비용과 품질을 저울질해 조절할 수 있고, 언제든 엔진을 바꿀 수 있다는 뜻입니다.</p>\n<h2 id=\"step-1--install-open-design\">1단계 — Open Design 설치하기</h2>\n<p>들어가는 길은 세 가지:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>방법</th><th>적합한 대상</th><th>요구 사항</th></tr></thead><tbody><tr><td><strong>데스크톱 앱</strong></td><td>대부분의 사람 — 설정 불필요</td><td>없음. 내려받아 열기만 하면 됩니다.</td></tr><tr><td><strong>소스에서 실행</strong></td><td>코드를 읽거나 수정하려는 개발자</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>내 에이전트에 설치</strong></td><td>터미널에서 사는 사람</td><td>기존 코딩 에이전트 CLI</td></tr></tbody></table>\n<p>가장 빠른 길은 <a href=\"https://open-design.ai/download\">open-design.ai/download</a>에서 받는 <strong>데스크톱 앱</strong>입니다 — 설치된 에이전트 CLI를 자동으로 감지합니다. 소스에서 실행하려면(Codedigipt의 방식):</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>출력된 로컬 URL을 여세요 — 동적 포트를 해석하므로 포트를 하드코딩하지 마세요. Codedigipt가 경험에서 짚어 주는 함정: <strong>Node 24</strong>가 필요합니다. Node 22에서는 그의 환경에서 시작되지 않았습니다. 먼저 Node 24 LTS를 설치하세요. Corepack이 고정된 pnpm 버전을 선택합니다.</p>\n<h2 id=\"step-2--choose-your-engine\">2단계 — 엔진 고르기</h2>\n<p>바로 이 단계가 중요합니다. 설정(실행 모드 구성)을 열고, Open Design이 머신에서 감지한 CLI 중에서 생성을 구동할 에이전트를 고르세요. 설치되지 않은 것은 비활성으로 표시됩니다.</p>\n<ul>\n<li><strong>Gemini CLI</strong> — 디자인 단계에서 Codedigipt의 선택: 디자인 감각이 좋고 무료 등급 크레딧도 오래갑니다. 생성은 그 크레딧으로 돌아갑니다.</li>\n<li><strong>Claude Code</strong> — 디자인에 강한 모델(Sonnet 또는 Opus)을 가리키면 가장 충실도 높은 결과물을 얻습니다.</li>\n<li><strong>OpenCode</strong> — 유능한 기본 모델(예: MiniMax, GLM)을 기본 탑재. 아무것도 설정하고 싶지 않다면 적합합니다.</li>\n<li><strong>Anthropic API(BYOK)</strong> — CLI가 없나요? API 키를 넣고 모델을 직접 고르면 됩니다. 이렇게 하면 <strong>별도의 Claude Design 구독 없이</strong> Claude 품질의 결과물을 쓸 수 있습니다 — 키는 여러분이, 디자인 표면은 Open Design이 가져옵니다.</li>\n</ul>\n<h2 id=\"step-3--generate-then-judge-by-engine\">3단계 — 먼저 생성하고, 엔진으로 판단하라</h2>\n<p>프로젝트를 만들고 이름을 붙인 뒤 <strong>고충실도</strong>를 선택하고 요청을 작성하세요(Codedigipt는 「auth-as-a-service」 API의 랜딩 페이지를 만듭니다). 무언가를 쓰기 전에 Open Design은 짧은 <strong>디스커버리 폼</strong>—출력 형식, 주요 화면, 대상 독자, 비주얼 톤, 브랜드 방향—을 돌려주어, 에이전트가 추측 대신 올바른 방향을 고정하도록 합니다. 답하고 비주얼 방향을 고르면 빌드가 시작됩니다.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/generated-prototype.webp\" alt=\"Open Design에서 생성된 실제 프로토타입.\">\n<em>미리보기에 렌더링된 실제 생성 프로토타입 — 어둡고 영화 같은 에이전시 랜딩 페이지.</em></p>\n<p>빠른 모델에서의 결과(Codedigipt는 Gemini flash 프리뷰 사용)는 수초 만에 나오는 깔끔하고 쓸 만한 초안입니다. 그가 거듭 강조하는 솔직한 단서: <strong>결과물은 여러분이 고른 모델 수준만큼 나온다.</strong> Opus급 다듬음이 필요하다고요? 엔진을 Opus의 Claude로 바꾸고 같은 요청을 다시 돌리세요 — 같은 스킬, 같은 디자인 시스템, 더 날카로운 결과.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/plugin-library.webp\" alt=\"설치 가능한 스킬이 포함된 Open Design 플러그인 라이브러리.\">\n<em>플러그인 라이브러리: 레지스트리에서 곧바로 스킬을 설치하세요 — anti-slop 디자인 스킬도 포함됩니다.</em></p>\n<p>마음에 들면 <strong>공유</strong> 메뉴에서 PDF, PPTX, 단독 HTML 또는 ZIP으로 내보낼 수 있습니다 — 또는 Vercel로 바로 배포할 수도 있습니다. 전체 플러그인 라이브러리는 <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>에서 둘러볼 수 있습니다.</p>\n<h2 id=\"tips\">팁</h2>\n<ul>\n<li><strong>모델을 작업에 맞춰라.</strong> 빠른 초안과 반복에는 저렴하고 빠른 모델을, 클라이언트에게 보일 최종본에는 최상급 모델을.</li>\n<li><strong>로컬 CLI를 쓰면</strong> 생성이 이미 가진 구독이나 무료 크레딧으로 돌아갑니다.</li>\n<li><strong>Claude Design 플랜 없이 Claude 품질을 원하면 BYOK</strong> — Anthropic 키를 설정에 넣고 모델을 선택하세요.</li>\n<li><strong>약한 모델 탓을 도구에 돌리지 마라.</strong> 좋은 디자인 시스템도 약한 엔진은 구하지 못합니다. 결과가 빈약해 보이면 프롬프트를 다시 쓰기 전에 모델부터 업그레이드하세요.</li>\n<li><strong>디스커버리 폼은 끝까지 채워라</strong> — 그것이 엔진이 첫 시도에 방향을 고정하는 방식입니다.</li>\n</ul>\n<h2 id=\"faq\">자주 묻는 질문</h2>\n<p><strong>고르는 모델이 정말 결과물을 그렇게 많이 바꾸나요?</strong>\n네 — 가장 큰 지렛대입니다. Open Design은 스킬과 디자인 시스템을 제공하지만, 디자인 판단은 엔진에서 나옵니다. 같은 요청이라도 Opus와 빠른 프리뷰 모델에서는 다듬음의 차이가 뚜렷합니다.</p>\n<p><strong>Claude Design 비용을 내지 않고 Claude 수준의 품질을 쓸 수 있나요?</strong>\n네. Open Design을 Claude Code로 가리키거나, Anthropic API 키를 설정에 넣고(BYOK) 모델을 고르세요. 별도의 Claude Design 구독 없이 그 결과물을 얻습니다.</p>\n<p><strong>프로젝트 도중에 모델을 바꿀 수 있나요?</strong>\n네 — 설정에서 에이전트/모델을 바꾸고 다시 돌리면 됩니다. 같은 스킬과 디자인 시스템, 그 뒤의 엔진만 달라집니다.</p>\n<p><strong>무료인가요?</strong>\n앱은 Apache-2.0 아래 오픈소스이며 로컬 실행은 무료입니다. 연결한 에이전트의 모델/크레딧 비용만 내면 됩니다.</p>\n<hr>\n<p><em>이 글 버전 가이드는 Codedigipt의 실습 워크스루를 바탕으로 합니다. 위의 전체 영상을 보시고, 더 실용적인 AI 도구 구성을 원하시면 <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">Codedigipt를 구독</a>하세요.</em></p>",
  },
  "de": {
    title: "Open Design — Mach aus dem Agenten, den du schon hast, eine Design-Engine",
    summary: "Ein praktischer Leitfaden zu dem Teil von Open Design, den die meisten Tutorials überspringen: das Modell dahinter zu wählen und auszutauschen. Dein Coding-Agent ist die Engine; das Modell, auf das du ihn richtest, ist der Qualitätsregler. Installiere es, binde Gemini CLI oder Claude an und lerne, das Modell zur Aufgabe passen zu lassen. Auf Basis von Codedigipts praktischem Walkthrough.",
    bodyHtml: "<p>Dieser Leitfaden konzentriert sich auf den Teil von Open Design, über den die meisten Walkthroughs hinweggehen: <strong>die Engine</strong>. Open Design selbst ist die Design-Oberfläche — die eigentliche Generierung erledigt der Coding-Agent und das Modell, auf das du es richtest, und genau diese Wahl ist der größte Hebel für die Ausgabequalität. Er folgt dem Setup, das <strong>Codedigipt</strong> in <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">seinem praktischen Walkthrough</a> verwendet, neu geschrieben und auf den aktuellen Release gebracht. Sieh dir das Video oben für den Live-Durchlauf an oder lies hier die schriftliche Fassung.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/workspace-home.webp\" alt=\"Der Open Design-Arbeitsbereich — beschreibe, was du möchtest, und wähle einen Modus.\">\n<em>Der Open Design-Arbeitsbereich: Beschreibe, was du erstellen willst, wähle einen Modus, und dein Agent erledigt den Rest.</em></p>\n<h2 id=\"what-is-open-design\">Was ist Open Design?</h2>\n<p>Open Design ist eine quelloffene, lokal-zuerst arbeitende Design-Plattform, die <strong>auf dem Coding-Agenten läuft, den du ohnehin nutzt</strong>. Sie bringt kein eigenes Modell mit — sie durchsucht deinen Rechner nach den CLIs, die du bereits hast (Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode und ein paar Dutzend mehr), und nutzt diesen Agenten als Design-Engine. So läuft die Arbeit über das Abo oder die Gratis-Credits, die du schon hast, statt über eine zweite Design-Rechnung.</p>\n<ul>\n<li><strong>Quelloffen, Apache-2.0</strong> — klone es, hoste es selbst, lies jede Zeile.</li>\n<li><strong>Läuft lokal</strong> — deine Projekte sind Ordner auf deinem eigenen Rechner.</li>\n<li><strong>Bring deine eigene Engine mit</strong> — jede unterstützte CLI oder dein eigener API-Schlüssel.</li>\n<li><strong>Eine umfangreiche Bibliothek an Designsystemen und Skills</strong> eingebaut, damit du nicht vor einer leeren Leinwand startest.</li>\n<li><strong>Mehr als Prototypen</strong> — Prototypen, Foliendecks, Bildgenerierung und Video.</li>\n</ul>\n<h2 id=\"the-key-idea-the-model-is-the-quality-knob\">Die Kernidee: Das Modell ist der Qualitätsregler</h2>\n<p>Hier ist das mentale Modell, bei dem Codedigipt landet, und es ist das Nützlichste zum Verinnerlichen: <strong>Die Ausgabequalität von Open Design folgt dem Modell, das du wählst.</strong> Open Design liefert die Struktur — Skills, Designsysteme, den Discovery-Flow —, doch das eigentliche Design-Urteil kommt von der Engine. Lass es auf einem schnellen, billigen Modell laufen und du bekommst einen schnellen, billigen Entwurf; lass es auf einem Spitzenmodell laufen und du bekommst aus demselben Prompt und Designsystem ein weitaus polierteres Ergebnis.</p>\n<p>Das ist ein Feature, keine Einschränkung. Es bedeutet, dass du pro Projekt Kosten gegen Qualität abwägen und jederzeit die Engine austauschen kannst.</p>\n<h2 id=\"step-1--install-open-design\">Schritt 1 — Open Design installieren</h2>\n<p>Drei Wege hinein:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Weg</th><th>Am besten für</th><th>Voraussetzungen</th></tr></thead><tbody><tr><td><strong>Desktop-App</strong></td><td>Die meisten Leute — keine Konfiguration</td><td>Keine. Einfach herunterladen und öffnen.</td></tr><tr><td><strong>Aus dem Quellcode ausführen</strong></td><td>Entwickler, die den Code lesen oder ändern wollen</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>In deinen Agenten installieren</strong></td><td>Leute, die im Terminal leben</td><td>Eine vorhandene Coding-Agent-CLI</td></tr></tbody></table>\n<p>Der schnellste Weg ist die <strong>Desktop-App</strong> von <a href=\"https://open-design.ai/download\">open-design.ai/download</a> — sie erkennt deine installierten Agent-CLIs automatisch. Um aus dem Quellcode auszuführen (Codedigipts Weg):</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Öffne die ausgegebene lokale URL — sie löst einen dynamischen Port auf, also kodiere keinen fest. Eine Stolperfalle, auf die Codedigipt aus Erfahrung hinweist: Du brauchst <strong>Node 24</strong>. Auf Node 22 ließ es sich bei ihm nicht starten; installiere zuerst Node 24 LTS. Corepack wählt die festgelegte pnpm-Version.</p>\n<h2 id=\"step-2--choose-your-engine\">Schritt 2 — Wähle deine Engine</h2>\n<p>Das ist der Schritt, auf den es ankommt. Öffne die Einstellungen (Ausführungsmodus konfigurieren) und wähle aus den CLIs, die Open Design auf deinem Rechner erkannt hat, den Agenten, der die Generierung antreiben soll. Alles Nicht-Installierte erscheint deaktiviert.</p>\n<ul>\n<li><strong>Gemini CLI</strong> — Codedigipts Wahl für die Designphase: starker Design-Instinkt, und die Credits der Gratis-Stufe reichen weit. Die Generierung läuft über diese Credits.</li>\n<li><strong>Claude Code</strong> — richte es auf ein designfähiges Modell (Sonnet oder Opus) für die höchste Ausgabetreue.</li>\n<li><strong>OpenCode</strong> — bringt fähige Standardmodelle mit (z. B. MiniMax, GLM), falls du lieber gar nichts konfigurieren willst.</li>\n<li><strong>Anthropic API (BYOK)</strong> — keine CLI? Trage einen API-Schlüssel ein und wähle das Modell direkt. So nutzt du Claude-Qualität <strong>ohne separates Claude-Design-Abo</strong> — du bringst den Schlüssel, Open Design bringt die Design-Oberfläche.</li>\n</ul>\n<h2 id=\"step-3--generate-then-judge-by-engine\">Schritt 3 — Generiere, dann beurteile nach Engine</h2>\n<p>Lege ein Projekt an, gib ihm einen Namen, wähle <strong>hohe Detailtreue</strong> und schreibe dein Briefing (Codedigipt baut eine Landingpage für eine „auth-as-a-service“-API). Bevor irgendetwas geschrieben wird, liefert Open Design ein kurzes <strong>Discovery-Formular</strong> — Ausgabeformat, primäre Oberfläche, Zielgruppe, visueller Ton, Markenrichtung —, damit der Agent die richtige Richtung festlegt, statt zu raten. Beantworte es, wähle eine visuelle Richtung, und es baut.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/generated-prototype.webp\" alt=\"Ein echter, in Open Design generierter Prototyp.\">\n<em>Ein echter generierter Prototyp in der Vorschau – eine dunkle, cineastische Agentur-Landingpage.</em></p>\n<p>Das Ergebnis auf einem schnellen Modell (Codedigipt nutzt eine Gemini-flash-Preview) ist ein sauberer, brauchbarer erster Wurf in Sekunden. Der ehrliche Vorbehalt, den er wiederholt: <strong>Du bekommst Ausgabe auf dem Niveau des Modells, das du gewählt hast.</strong> Du willst Opus-Politur? Stelle die Engine auf Claude mit Opus um und lass dasselbe Briefing erneut laufen — gleicher Skill, gleiches Designsystem, schärferes Ergebnis.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/plugin-library.webp\" alt=\"Die Plugin-Bibliothek von Open Design mit installierbaren Skills.\">\n<em>Die Plugin-Bibliothek: installiere Skills direkt aus der Registry – einschließlich Anti-Slop-Design-Skills.</em></p>\n<p>Wenn du zufrieden bist, exportiert das <strong>Teilen</strong>-Menü nach PDF, PPTX, eigenständigem HTML oder einem ZIP — oder deployt direkt auf Vercel. Die vollständige Plugin-Bibliothek kannst du unter <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> durchstöbern.</p>\n<h2 id=\"tips\">Tipps</h2>\n<ul>\n<li><strong>Passe das Modell zur Aufgabe an.</strong> Billiges/schnelles Modell für rasche Entwürfe und Iteration; Spitzenmodell für den finalen, kundengerichteten Durchlauf.</li>\n<li><strong>Nutze eine lokale CLI</strong>, damit die Generierung über ein Abo oder Gratis-Credits läuft, die du schon hast.</li>\n<li><strong>BYOK für Claude-Qualität ohne Claude-Design-Plan</strong> — trage einen Anthropic-Schlüssel in die Einstellungen ein und wähle das Modell.</li>\n<li><strong>Schiebe ein schwaches Modell nicht dem Werkzeug in die Schuhe.</strong> Ein gutes Designsystem kann eine schwache Engine nicht retten; wirkt die Ausgabe dünn, rüste das Modell auf, bevor du den Prompt umschreibst.</li>\n<li><strong>Beantworte das Discovery-Formular vollständig</strong> — so legt die Engine beim ersten Versuch die Richtung fest.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Ändert das Modell, das ich wähle, die Ausgabe wirklich so stark?</strong>\nJa — es ist der größte Hebel. Open Design liefert die Skills und Designsysteme, aber das Design-Urteil kommt von der Engine. Dasselbe Briefing auf Opus gegenüber einem schnellen Preview-Modell erzeugt spürbar unterschiedliche Politur.</p>\n<p><strong>Kann ich Claude-Qualität nutzen, ohne für Claude Design zu zahlen?</strong>\nJa. Richte Open Design auf Claude Code oder trage einen Anthropic-API-Schlüssel in die Einstellungen ein (BYOK) und wähle das Modell. Du bekommst die Ausgabe ohne separates Claude-Design-Abo.</p>\n<p><strong>Kann ich Modelle mitten im Projekt wechseln?</strong>\nJa — ändere Agent/Modell in den Einstellungen und lass es erneut laufen. Gleicher Skill und gleiches Designsystem, eine andere Engine dahinter.</p>\n<p><strong>Ist es kostenlos?</strong>\nDie App ist unter Apache-2.0 quelloffen und lokal kostenlos ausführbar. Du zahlst nur für das Modell bzw. die Credits des jeweils verbundenen Agenten.</p>\n<hr>\n<p><em>Dieser schriftliche Leitfaden basiert auf Codedigipts praktischem Walkthrough. Sieh dir oben das ganze Video an und <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">abonniere Codedigipt</a> für mehr praktische Setups von KI-Tools.</em></p>",
  },
  "fr": {
    title: "Open Design — Transformez l’agent que vous avez déjà en moteur de design",
    summary: "Un guide pratique sur la partie d’Open Design que la plupart des tutoriels passent sous silence : choisir et remplacer le modèle qui le fait tourner. Votre agent de codage est le moteur ; le modèle sur lequel vous le pointez est le bouton de qualité. Installez-le, branchez Gemini CLI ou Claude, et apprenez à accorder le modèle à la tâche. D’après la démonstration pratique de Codedigipt.",
    bodyHtml: "<p>Ce guide se concentre sur la partie d’Open Design que la plupart des démonstrations effleurent : <strong>le moteur</strong>. Open Design n’est que la surface de design — la génération réelle est faite par l’agent de codage et le modèle sur lesquels vous le pointez, et ce choix est le plus grand levier sur la qualité du rendu. Il suit la configuration que <strong>Codedigipt</strong> utilise dans <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">sa démonstration pratique</a>, réécrite et mise à jour pour la version actuelle. Regardez la vidéo ci-dessus pour le déroulé en direct, ou lisez la version écrite ci-après.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/workspace-home.webp\" alt=\"L'espace de travail Open Design — décrivez ce que vous voulez et choisissez un mode.\">\n<em>L'espace de travail Open Design : décrivez ce que vous voulez créer, choisissez un mode, et votre agent fait le reste.</em></p>\n<h2 id=\"what-is-open-design\">Qu’est-ce qu’Open Design ?</h2>\n<p>Open Design est une plateforme de design open source et local-first qui tourne <strong>par-dessus l’agent de codage que vous utilisez déjà</strong>. Elle n’embarque pas son propre modèle — elle scanne votre machine à la recherche des CLI que vous avez déjà (Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode, et quelques dizaines d’autres) et se sert de cet agent comme moteur de design. Le travail tourne donc sur l’abonnement ou les crédits gratuits que vous avez déjà, pas sur une seconde facture de design.</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — clonez-le, auto-hébergez-le, lisez chaque ligne.</li>\n<li><strong>Fonctionne en local</strong> — vos projets sont des dossiers sur votre propre machine.</li>\n<li><strong>Apportez votre propre moteur</strong> — n’importe quelle CLI prise en charge, ou votre propre clé API.</li>\n<li><strong>Une riche bibliothèque de design systems et de compétences</strong> intégrée, pour ne pas partir d’un canevas vierge.</li>\n<li><strong>Plus que des prototypes</strong> — prototypes, présentations, génération d’images et vidéo.</li>\n</ul>\n<h2 id=\"the-key-idea-the-model-is-the-quality-knob\">L’idée clé : le modèle est le bouton de qualité</h2>\n<p>Voici le modèle mental auquel Codedigipt aboutit, et c’est la chose la plus utile à intérioriser : <strong>la qualité du rendu d’Open Design suit le modèle que vous choisissez.</strong> Open Design fournit la structure — compétences, design systems, le flux de découverte — mais le véritable jugement de design vient du moteur. Faites-le tourner sur un modèle rapide et bon marché, vous obtenez un brouillon rapide et bon marché ; faites-le tourner sur un modèle haut de gamme, et vous obtenez un résultat bien plus abouti à partir du même prompt et du même design system.</p>\n<p>C’est une fonctionnalité, pas une limite. Cela signifie que vous pouvez doser le coût face à la qualité projet par projet, et changer de moteur quand bon vous semble.</p>\n<h2 id=\"step-1--install-open-design\">Étape 1 — Installer Open Design</h2>\n<p>Trois portes d’entrée :</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Voie</th><th>Idéal pour</th><th>Prérequis</th></tr></thead><tbody><tr><td><strong>Application de bureau</strong></td><td>La plupart des gens — zéro configuration</td><td>Aucun. Téléchargez et ouvrez, c’est tout.</td></tr><tr><td><strong>Exécuter depuis les sources</strong></td><td>Les développeurs qui veulent lire ou modifier le code</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Installer dans votre agent</strong></td><td>Ceux qui vivent dans le terminal</td><td>Une CLI d’agent de codage existante</td></tr></tbody></table>\n<p>La voie la plus rapide est l’<strong>application de bureau</strong> depuis <a href=\"https://open-design.ai/download\">open-design.ai/download</a> — elle détecte automatiquement vos CLI d’agents installées. Pour exécuter depuis les sources (la voie de Codedigipt) :</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Ouvrez l’URL locale qu’elle affiche — elle résout un port dynamique, donc n’en codez aucun en dur. Un piège que Codedigipt signale par expérience : il vous faut <strong>Node 24</strong>. Sur Node 22, ça ne démarrait pas chez lui ; installez d’abord Node 24 LTS. Corepack sélectionne la version épinglée de pnpm.</p>\n<h2 id=\"step-2--choose-your-engine\">Étape 2 — Choisissez votre moteur</h2>\n<p>C’est l’étape qui compte. Ouvrez les réglages (configurer le mode d’exécution) et choisissez, parmi les CLI qu’Open Design a détectées sur votre machine, l’agent qui pilotera la génération. Tout ce qui n’est pas installé apparaît désactivé.</p>\n<ul>\n<li><strong>Gemini CLI</strong> — le choix de Codedigipt pour la phase de design : un solide instinct de design, et les crédits de l’offre gratuite vont loin. La génération s’appuie sur ces crédits.</li>\n<li><strong>Claude Code</strong> — pointez-le sur un modèle apte au design (Sonnet ou Opus) pour le rendu le plus fidèle.</li>\n<li><strong>OpenCode</strong> — livré avec des modèles par défaut compétents (p. ex. MiniMax, GLM) si vous préférez ne rien configurer.</li>\n<li><strong>API Anthropic (BYOK)</strong> — pas de CLI ? Insérez une clé API et choisissez le modèle directement. Cela vous permet d’utiliser un rendu de qualité Claude <strong>sans abonnement Claude Design distinct</strong> — vous apportez la clé, Open Design apporte la surface de design.</li>\n</ul>\n<h2 id=\"step-3--generate-then-judge-by-engine\">Étape 3 — Générez, puis jugez selon le moteur</h2>\n<p>Créez un projet, donnez-lui un nom, choisissez la <strong>haute fidélité</strong> et rédigez votre brief (Codedigipt construit une page d’atterrissage pour une API « auth-as-a-service »). Avant d’écrire quoi que ce soit, Open Design renvoie un court <strong>formulaire de découverte</strong> — format de sortie, surface principale, audience, ton visuel, direction de marque — afin que l’agent verrouille la bonne direction au lieu de deviner. Répondez-y, choisissez une direction visuelle, et il construit.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/generated-prototype.webp\" alt=\"Un véritable prototype généré dans Open Design.\">\n<em>Un véritable prototype généré, rendu dans l'aperçu — une landing page d'agence sombre et cinématographique.</em></p>\n<p>Le résultat sur un modèle rapide (Codedigipt utilise une préversion Gemini flash) est une première mouture propre et utilisable en quelques secondes. La réserve honnête qu’il répète : <strong>vous obtenez un rendu au niveau du modèle que vous avez choisi.</strong> Envie d’un fini de calibre Opus ? Basculez le moteur sur Claude avec Opus et relancez le même brief — même compétence, même design system, résultat plus net.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/plugin-library.webp\" alt=\"La bibliothèque de plugins d'Open Design, avec des skills installables.\">\n<em>La bibliothèque de plugins : installez des skills directement depuis le registre — y compris des skills de design anti-slop.</em></p>\n<p>Une fois satisfait, le menu <strong>Partager</strong> exporte en PDF, PPTX, HTML autonome ou ZIP — ou déploie directement sur Vercel. Vous pouvez parcourir la bibliothèque complète de plugins sur <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"tips\">Astuces</h2>\n<ul>\n<li><strong>Accordez le modèle à la tâche.</strong> Un modèle bon marché/rapide pour les brouillons rapides et l’itération ; un modèle haut de gamme pour la passe finale destinée au client.</li>\n<li><strong>Utilisez une CLI locale</strong> pour que la génération s’appuie sur un abonnement ou des crédits gratuits que vous avez déjà.</li>\n<li><strong>BYOK pour une qualité Claude sans plan Claude Design</strong> — déposez une clé Anthropic dans les réglages et sélectionnez le modèle.</li>\n<li><strong>Ne blâmez pas l’outil pour un modèle faible.</strong> Un bon design system ne peut pas sauver un moteur faible ; si le rendu paraît maigre, améliorez le modèle avant de réécrire le prompt.</li>\n<li><strong>Remplissez entièrement le formulaire de découverte</strong> — c’est ainsi que le moteur verrouille la direction du premier coup.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Le modèle que je choisis change-t-il vraiment autant le rendu ?</strong>\nOui — c’est le plus grand levier. Open Design fournit les compétences et les design systems, mais le jugement de design vient du moteur. Le même brief sur Opus comparé à un modèle de préversion rapide produit un fini nettement différent.</p>\n<p><strong>Puis-je obtenir une qualité de niveau Claude sans payer pour Claude Design ?</strong>\nOui. Pointez Open Design sur Claude Code, ou déposez une clé API Anthropic dans les réglages (BYOK) et sélectionnez le modèle. Vous obtenez le rendu sans abonnement Claude Design distinct.</p>\n<p><strong>Puis-je changer de modèle en cours de projet ?</strong>\nOui — changez l’agent/le modèle dans les réglages et relancez. Même compétence et même design system, un autre moteur derrière.</p>\n<p><strong>Est-ce gratuit ?</strong>\nL’application est open source sous Apache-2.0 et s’exécute gratuitement en local. Vous ne payez que le modèle/les crédits de l’agent que vous connectez.</p>\n<hr>\n<p><em>Ce guide écrit s’appuie sur la démonstration pratique de Codedigipt. Regardez la vidéo complète ci-dessus et <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">abonnez-vous à Codedigipt</a> pour davantage de configurations pratiques d’outils d’IA.</em></p>",
  },
  "ru": {
    title: "Open Design — Превратите уже имеющегося агента в движок дизайна",
    summary: "Практическое руководство по той части Open Design, которую большинство туториалов пропускает, — как выбрать и заменить модель, стоящую за ним. Ваш кодинг-агент — это движок; модель, на которую вы его нацеливаете, — регулятор качества. Установите его, подключите Gemini CLI или Claude и научитесь подбирать модель под задачу. По мотивам практического разбора от Codedigipt.",
    bodyHtml: "<p>Это руководство посвящено той части Open Design, которую большинство разборов проскакивает: <strong>движку</strong>. Сам Open Design — лишь поверхность дизайна, а реальную генерацию выполняют кодинг-агент и модель, на которые вы его нацеливаете, и именно этот выбор сильнее всего влияет на качество результата. Оно повторяет конфигурацию, которую <strong>Codedigipt</strong> использует в <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">своём практическом разборе</a>, переписанную и обновлённую под текущий релиз. Смотрите видео выше для живого прогона или читайте текстовую версию ниже.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/workspace-home.webp\" alt=\"Рабочее пространство Open Design — опишите, что вам нужно, и выберите режим.\">\n<em>Рабочее пространство Open Design: опишите, что хотите создать, выберите режим, а остальное сделает ваш агент.</em></p>\n<h2 id=\"what-is-open-design\">Что такое Open Design?</h2>\n<p>Open Design — это опенсорсная, локальная в первую очередь платформа дизайна, которая работает <strong>поверх кодинг-агента, которым вы уже пользуетесь</strong>. Она не несёт собственной модели — она сканирует вашу машину на предмет уже имеющихся CLI (Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode и ещё пара десятков) и использует этого агента как движок дизайна. Поэтому работа идёт на подписке или бесплатных кредитах, которые у вас уже есть, а не на втором счёте за дизайн.</p>\n<ul>\n<li><strong>Открытый исходный код, Apache-2.0</strong> — клонируйте, разворачивайте у себя, читайте каждую строку.</li>\n<li><strong>Работает локально</strong> — ваши проекты — это папки на вашей собственной машине.</li>\n<li><strong>Свой движок на ваш выбор</strong> — любой поддерживаемый CLI или ваш собственный ключ API.</li>\n<li><strong>Встроенная обширная библиотека дизайн-систем и навыков</strong>, чтобы не начинать с пустого холста.</li>\n<li><strong>Больше, чем прототипы</strong> — прототипы, слайды, генерация изображений и видео.</li>\n</ul>\n<h2 id=\"the-key-idea-the-model-is-the-quality-knob\">Ключевая мысль: модель — это регулятор качества</h2>\n<p>Вот ментальная модель, к которой приходит Codedigipt, и это самое полезное, что стоит усвоить: <strong>качество результата Open Design следует за выбранной вами моделью.</strong> Open Design даёт структуру — навыки, дизайн-системы, поток обнаружения, — но само дизайнерское суждение исходит от движка. Запустите на быстрой дешёвой модели — получите быстрый дешёвый черновик; запустите на топовой модели — и из того же промпта и дизайн-системы получите куда более отполированный результат.</p>\n<p>Это возможность, а не ограничение. Это значит, что вы можете для каждого проекта выбирать баланс между стоимостью и качеством и менять движок когда угодно.</p>\n<h2 id=\"step-1--install-open-design\">Шаг 1 — Установите Open Design</h2>\n<p>Три пути входа:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Путь</th><th>Кому подходит</th><th>Требования</th></tr></thead><tbody><tr><td><strong>Десктоп-приложение</strong></td><td>Большинству — без настройки</td><td>Ничего. Просто скачайте и откройте.</td></tr><tr><td><strong>Запуск из исходников</strong></td><td>Разработчикам, желающим читать или менять код</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Установка в вашего агента</strong></td><td>Тем, кто живёт в терминале</td><td>Имеющийся CLI кодинг-агента</td></tr></tbody></table>\n<p>Самый быстрый путь — <strong>десктоп-приложение</strong> с <a href=\"https://open-design.ai/download\">open-design.ai/download</a>: оно автоматически обнаруживает установленные CLI агентов. Чтобы запустить из исходников (путь Codedigipt):</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Откройте локальный URL, который оно выводит, — оно определяет динамический порт, так что не прописывайте его жёстко. Одна ловушка, на которую Codedigipt указывает по опыту: нужен <strong>Node 24</strong>. На Node 22 у него не запускалось; сначала установите Node 24 LTS. Corepack выберет закреплённую версию pnpm.</p>\n<h2 id=\"step-2--choose-your-engine\">Шаг 2 — Выберите движок</h2>\n<p>Это и есть тот самый важный шаг. Откройте настройки (настроить режим выполнения) и выберите среди CLI, которые Open Design обнаружил на вашей машине, агента, который будет вести генерацию. Всё неустановленное показывается как недоступное.</p>\n<ul>\n<li><strong>Gemini CLI</strong> — выбор Codedigipt для этапа дизайна: сильное чутьё на дизайн, а кредитов бесплатного уровня хватает надолго. Генерация идёт на этих кредитах.</li>\n<li><strong>Claude Code</strong> — нацельте его на модель, сильную в дизайне (Sonnet или Opus), ради результата высшей точности.</li>\n<li><strong>OpenCode</strong> — поставляется с дельными моделями по умолчанию (например, MiniMax, GLM), если вы предпочли бы ничего не настраивать.</li>\n<li><strong>Anthropic API (BYOK)</strong> — нет CLI? Вставьте ключ API и выберите модель напрямую. Это позволяет получить результат уровня Claude <strong>без отдельной подписки Claude Design</strong>: вы приносите ключ, Open Design — поверхность дизайна.</li>\n</ul>\n<h2 id=\"step-3--generate-then-judge-by-engine\">Шаг 3 — Сгенерируйте, затем судите по движку</h2>\n<p>Создайте проект, дайте ему имя, выберите <strong>высокую детализацию</strong> и напишите бриф (Codedigipt строит лендинг для API в духе «auth-as-a-service»). Прежде чем что-либо писать, Open Design возвращает короткую <strong>форму обнаружения</strong> — формат вывода, основную поверхность, аудиторию, визуальный тон, направление бренда, — чтобы агент зафиксировал верное направление, а не гадал. Ответьте на неё, выберите визуальное направление — и он строит.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/generated-prototype.webp\" alt=\"Реальный прототип, сгенерированный в Open Design.\">\n<em>Реальный сгенерированный прототип в предпросмотре — тёмная, кинематографичная лендинг-страница агентства.</em></p>\n<p>Результат на быстрой модели (Codedigipt использует превью Gemini flash) — чистый, пригодный к работе первый проход за секунды. Честная оговорка, которую он повторяет: <strong>вы получаете результат на уровне выбранной модели.</strong> Хотите отделки уровня Opus? Переключите движок на Claude с Opus и прогоните тот же бриф заново — тот же навык, та же дизайн-система, более выверенный результат.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/plugin-library.webp\" alt=\"Библиотека плагинов Open Design с устанавливаемыми навыками.\">\n<em>Библиотека плагинов: устанавливайте навыки прямо из реестра — включая дизайн-навыки против «слопа» (anti-slop).</em></p>\n<p>Когда вас всё устроит, меню <strong>Поделиться</strong> экспортирует в PDF, PPTX, автономный HTML или ZIP — либо разворачивает прямо на Vercel. Просмотреть полную библиотеку плагинов можно на <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"tips\">Советы</h2>\n<ul>\n<li><strong>Подбирайте модель под задачу.</strong> Дешёвая/быстрая модель — для быстрых черновиков и итераций; топовая модель — для финального прохода, который увидит клиент.</li>\n<li><strong>Используйте локальный CLI</strong>, чтобы генерация шла на подписке или бесплатных кредитах, которые у вас уже есть.</li>\n<li><strong>BYOK ради качества Claude без плана Claude Design</strong> — вставьте ключ Anthropic в настройки и выберите модель.</li>\n<li><strong>Не вините инструмент за слабую модель.</strong> Хорошая дизайн-система не спасёт слабый движок; если результат выглядит блёкло, сначала обновите модель, а не переписывайте промпт.</li>\n<li><strong>Заполняйте форму обнаружения полностью</strong> — именно так движок фиксирует направление с первой попытки.</li>\n</ul>\n<h2 id=\"faq\">Частые вопросы</h2>\n<p><strong>Неужели выбранная модель так сильно меняет результат?</strong>\nДа — это самый большой рычаг. Open Design предоставляет навыки и дизайн-системы, но дизайнерское суждение исходит от движка. Один и тот же бриф на Opus и на быстрой превью-модели даёт заметно разную отделку.</p>\n<p><strong>Можно ли получить качество уровня Claude, не платя за Claude Design?</strong>\nДа. Нацельте Open Design на Claude Code или вставьте ключ API Anthropic в настройки (BYOK) и выберите модель. Вы получите результат без отдельной подписки Claude Design.</p>\n<p><strong>Можно ли менять модели посреди проекта?</strong>\nДа — поменяйте агента/модель в настройках и прогоните заново. Тот же навык и та же дизайн-система, но движок за ними другой.</p>\n<p><strong>Это бесплатно?</strong>\nПриложение опенсорсное под Apache-2.0 и бесплатно для локального запуска. Вы платите лишь за модель/кредиты того агента, которого подключаете.</p>\n<hr>\n<p><em>Это текстовое руководство основано на практическом разборе Codedigipt. Посмотрите полное видео выше и <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">подпишитесь на Codedigipt</a>, чтобы увидеть больше практичных настроек ИИ-инструментов.</em></p>",
  },
  "es": {
    title: "Open Design: convierte el agente que ya tienes en un motor de diseño",
    summary: "Una guía práctica sobre la parte de Open Design que la mayoría de los tutoriales se salta: elegir y cambiar el modelo que hay detrás. Tu agente de codificación es el motor; el modelo al que lo apuntas es la perilla de calidad. Instálalo, conecta Gemini CLI o Claude y aprende a ajustar el modelo a la tarea. Basado en el recorrido práctico de Codedigipt.",
    bodyHtml: "<p>Esta guía se centra en la parte de Open Design que la mayoría de los recorridos pasa por alto: <strong>el motor</strong>. Open Design en sí es la superficie de diseño; la generación real la hace el agente de codificación y el modelo a los que lo apuntes, y esa elección es la mayor palanca sobre la calidad del resultado. Sigue la configuración que <strong>Codedigipt</strong> utiliza en <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">su recorrido práctico</a>, reescrita y actualizada a la versión actual. Mira el video de arriba para ver la ejecución en vivo, o sigue leyendo la versión escrita.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/workspace-home.webp\" alt=\"El espacio de trabajo de Open Design: describe lo que quieres y elige un modo.\">\n<em>El espacio de trabajo de Open Design: describe lo que quieres crear, elige un modo y tu agente hace el resto.</em></p>\n<h2 id=\"what-is-open-design\">¿Qué es Open Design?</h2>\n<p>Open Design es una plataforma de diseño de código abierto y local-first que se ejecuta <strong>sobre el agente de codificación que ya usas</strong>. No trae su propio modelo: escanea tu máquina en busca de los CLI que ya tienes (Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode y un par de docenas más) y usa ese agente como motor de diseño. Así, el trabajo corre sobre la suscripción o los créditos gratuitos que ya tienes, no sobre una segunda factura de diseño.</p>\n<ul>\n<li><strong>Código abierto, Apache-2.0</strong>: clónalo, autoaloja, lee cada línea.</li>\n<li><strong>Se ejecuta en local</strong>: tus proyectos son carpetas en tu propia máquina.</li>\n<li><strong>Trae tu propio motor</strong>: cualquier CLI compatible o tu propia clave de API.</li>\n<li><strong>Una nutrida biblioteca de sistemas de diseño y habilidades</strong> integrada, para no empezar desde un lienzo en blanco.</li>\n<li><strong>Más que prototipos</strong>: prototipos, presentaciones, generación de imágenes y video.</li>\n</ul>\n<h2 id=\"the-key-idea-the-model-is-the-quality-knob\">La idea clave: el modelo es la perilla de calidad</h2>\n<p>Este es el modelo mental al que llega Codedigipt, y es lo más útil de interiorizar: <strong>la calidad del resultado de Open Design sigue al modelo que elijas.</strong> Open Design aporta la estructura —habilidades, sistemas de diseño, el flujo de descubrimiento—, pero el verdadero criterio de diseño proviene del motor. Ejecútalo en un modelo rápido y barato y obtienes un borrador rápido y barato; ejecútalo en un modelo de primer nivel y obtienes un resultado mucho más pulido a partir del mismo prompt y sistema de diseño.</p>\n<p>Eso es una virtud, no una limitación. Significa que puedes equilibrar costo frente a calidad por proyecto y cambiar de motor cuando quieras.</p>\n<h2 id=\"step-1--install-open-design\">Paso 1: Instalar Open Design</h2>\n<p>Tres vías de entrada:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Vía</th><th>Ideal para</th><th>Requisitos</th></tr></thead><tbody><tr><td><strong>Aplicación de escritorio</strong></td><td>La mayoría de la gente: cero configuración</td><td>Ninguno. Solo descarga y abre.</td></tr><tr><td><strong>Ejecutar desde el código fuente</strong></td><td>Desarrolladores que quieren leer o modificar el código</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Instalar en tu agente</strong></td><td>Quienes viven en la terminal</td><td>Un CLI de agente de codificación existente</td></tr></tbody></table>\n<p>La vía más rápida es la <strong>aplicación de escritorio</strong> desde <a href=\"https://open-design.ai/download\">open-design.ai/download</a>: detecta automáticamente los CLI de agentes que tienes instalados. Para ejecutar desde el código fuente (la vía de Codedigipt):</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abre la URL local que imprime: resuelve un puerto dinámico, así que no fijes ninguno en el código. Un tropiezo que Codedigipt señala por experiencia: necesitas <strong>Node 24</strong>. En Node 22 no le arrancaba; instala primero Node 24 LTS. Corepack selecciona la versión fijada de pnpm.</p>\n<h2 id=\"step-2--choose-your-engine\">Paso 2: Elige tu motor</h2>\n<p>Este es el paso que importa. Abre los ajustes (configurar el modo de ejecución) y elige, entre los CLI que Open Design detectó en tu máquina, el agente que impulsará la generación. Todo lo que no esté instalado aparece deshabilitado.</p>\n<ul>\n<li><strong>Gemini CLI</strong>: la elección de Codedigipt para la fase de diseño: buen instinto de diseño y los créditos del nivel gratuito rinden mucho. La generación se apoya en esos créditos.</li>\n<li><strong>Claude Code</strong>: apúntalo a un modelo apto para diseño (Sonnet u Opus) para obtener el resultado de mayor fidelidad.</li>\n<li><strong>OpenCode</strong>: viene con modelos predeterminados competentes (p. ej., MiniMax, GLM) si prefieres no configurar nada.</li>\n<li><strong>API de Anthropic (BYOK)</strong>: ¿sin CLI? Coloca una clave de API y elige el modelo directamente. Esto te permite usar resultados de calidad Claude <strong>sin una suscripción aparte a Claude Design</strong>: tú pones la clave, Open Design pone la superficie de diseño.</li>\n</ul>\n<h2 id=\"step-3--generate-then-judge-by-engine\">Paso 3: Genera y luego juzga según el motor</h2>\n<p>Crea un proyecto, ponle nombre, elige <strong>alta fidelidad</strong> y escribe tu encargo (Codedigipt construye una página de aterrizaje para una API de tipo «auth-as-a-service»). Antes de escribir nada, Open Design devuelve un breve <strong>formulario de descubrimiento</strong> —formato de salida, superficie principal, audiencia, tono visual, dirección de marca— para que el agente fije la dirección correcta en lugar de adivinar. Respóndelo, elige una dirección visual y construye.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/generated-prototype.webp\" alt=\"Un prototipo real generado en Open Design.\">\n<em>Un prototipo real generado, renderizado en la vista previa: una landing page de agencia oscura y cinematográfica.</em></p>\n<p>El resultado en un modelo rápido (Codedigipt usa una vista previa de Gemini flash) es una primera pasada limpia y utilizable en segundos. La advertencia honesta que repite: <strong>obtienes un resultado al nivel del modelo que elegiste.</strong> ¿Quieres un acabado de calibre Opus? Cambia el motor a Claude con Opus y vuelve a ejecutar el mismo encargo: misma habilidad, mismo sistema de diseño, resultado más nítido.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/plugin-library.webp\" alt=\"La biblioteca de plugins de Open Design, con skills instalables.\">\n<em>La biblioteca de plugins: instala skills directamente desde el registro, incluidos skills de diseño anti-slop.</em></p>\n<p>Cuando estés conforme, el menú <strong>Compartir</strong> exporta a PDF, PPTX, HTML independiente o un ZIP, o lo despliega directamente en Vercel. Puedes explorar la biblioteca completa de plugins en <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"tips\">Consejos</h2>\n<ul>\n<li><strong>Ajusta el modelo a la tarea.</strong> Modelo barato/rápido para borradores rápidos e iteración; modelo de primer nivel para la pasada final que verá el cliente.</li>\n<li><strong>Usa un CLI local</strong> para que la generación se apoye en una suscripción o créditos gratuitos que ya tengas.</li>\n<li><strong>BYOK para calidad Claude sin un plan de Claude Design</strong>: coloca una clave de Anthropic en los ajustes y selecciona el modelo.</li>\n<li><strong>No culpes a la herramienta por un modelo débil.</strong> Un buen sistema de diseño no puede rescatar a un motor débil; si el resultado se ve pobre, mejora el modelo antes de reescribir el prompt.</li>\n<li><strong>Responde el formulario de descubrimiento por completo</strong>: así es como el motor fija la dirección al primer intento.</li>\n</ul>\n<h2 id=\"faq\">Preguntas frecuentes</h2>\n<p><strong>¿De verdad el modelo que elijo cambia tanto el resultado?</strong>\nSí: es la mayor palanca. Open Design aporta las habilidades y los sistemas de diseño, pero el criterio de diseño proviene del motor. El mismo encargo en Opus frente a un modelo de vista previa rápido produce un acabado notablemente distinto.</p>\n<p><strong>¿Puedo obtener calidad de nivel Claude sin pagar por Claude Design?</strong>\nSí. Apunta Open Design a Claude Code, o coloca una clave de API de Anthropic en los ajustes (BYOK) y selecciona el modelo. Obtienes el resultado sin una suscripción aparte a Claude Design.</p>\n<p><strong>¿Puedo cambiar de modelo a mitad de un proyecto?</strong>\nSí: cambia el agente/modelo en los ajustes y vuelve a ejecutar. La misma habilidad y el mismo sistema de diseño, con un motor distinto detrás.</p>\n<p><strong>¿Es gratis?</strong>\nLa aplicación es de código abierto bajo Apache-2.0 y gratuita para ejecutar en local. Solo pagas por el modelo/los créditos del agente que conectes.</p>\n<hr>\n<p><em>Esta guía escrita se basa en el recorrido práctico de Codedigipt. Mira el video completo arriba y <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">suscríbete a Codedigipt</a> para más configuraciones prácticas de herramientas de IA.</em></p>",
  },
  "pt-br": {
    title: "Open Design — Transforme o agente que você já tem em um motor de design",
    summary: "Um guia prático sobre a parte do Open Design que a maioria dos tutoriais pula: escolher e trocar o modelo por trás dele. Seu agente de codificação é o motor; o modelo para o qual você o aponta é o botão de qualidade. Instale-o, conecte o Gemini CLI ou o Claude e aprenda a casar o modelo com a tarefa. Baseado no passo a passo prático do Codedigipt.",
    bodyHtml: "<p>Este guia foca a parte do Open Design que a maioria dos passo a passo deixa de lado: <strong>o motor</strong>. O Open Design em si é a superfície de design — a geração de verdade é feita pelo agente de codificação e pelo modelo para os quais você o aponta, e essa escolha é a maior alavanca sobre a qualidade do resultado. Ele segue a configuração que o <strong>Codedigipt</strong> usa em <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">seu passo a passo prático</a>, reescrita e atualizada para a versão atual. Assista ao vídeo acima para ver a execução ao vivo, ou continue lendo a versão escrita.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/workspace-home.webp\" alt=\"O espaço de trabalho do Open Design — descreva o que você quer e escolha um modo.\">\n<em>O espaço de trabalho do Open Design: descreva o que você quer criar, escolha um modo e seu agente faz o resto.</em></p>\n<h2 id=\"what-is-open-design\">O que é o Open Design?</h2>\n<p>O Open Design é uma plataforma de design de código aberto e local-first que roda <strong>sobre o agente de codificação que você já usa</strong>. Ele não traz um modelo próprio — varre sua máquina em busca dos CLIs que você já tem (Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode e mais algumas dezenas) e usa esse agente como motor de design. Assim, o trabalho roda na assinatura ou nos créditos gratuitos que você já tem, e não em uma segunda conta de design.</p>\n<ul>\n<li><strong>Código aberto, Apache-2.0</strong> — clone, hospede você mesmo, leia cada linha.</li>\n<li><strong>Roda localmente</strong> — seus projetos são pastas na sua própria máquina.</li>\n<li><strong>Traga seu próprio motor</strong> — qualquer CLI compatível ou sua própria chave de API.</li>\n<li><strong>Uma vasta biblioteca de design systems e habilidades</strong> embutida, para você não começar de uma tela em branco.</li>\n<li><strong>Mais do que protótipos</strong> — protótipos, apresentações, geração de imagens e vídeo.</li>\n</ul>\n<h2 id=\"the-key-idea-the-model-is-the-quality-knob\">A ideia central: o modelo é o botão de qualidade</h2>\n<p>Este é o modelo mental ao qual o Codedigipt chega, e é a coisa mais útil para internalizar: <strong>a qualidade do resultado do Open Design acompanha o modelo que você escolhe.</strong> O Open Design fornece a estrutura — habilidades, design systems, o fluxo de descoberta —, mas o juízo de design de fato vem do motor. Rode num modelo rápido e barato e você tem um rascunho rápido e barato; rode num modelo de ponta e você tem um resultado bem mais refinado a partir do mesmo prompt e design system.</p>\n<p>Isso é um recurso, não uma limitação. Significa que você pode equilibrar custo e qualidade por projeto e trocar de motor quando quiser.</p>\n<h2 id=\"step-1--install-open-design\">Passo 1 — Instalar o Open Design</h2>\n<p>Três caminhos de entrada:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Caminho</th><th>Melhor para</th><th>Requisitos</th></tr></thead><tbody><tr><td><strong>Aplicativo desktop</strong></td><td>A maioria das pessoas — configuração zero</td><td>Nenhum. É só baixar e abrir.</td></tr><tr><td><strong>Rodar a partir do código-fonte</strong></td><td>Desenvolvedores que querem ler ou alterar o código</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Instalar no seu agente</strong></td><td>Quem vive no terminal</td><td>Um CLI de agente de codificação já existente</td></tr></tbody></table>\n<p>O caminho mais rápido é o <strong>aplicativo desktop</strong> em <a href=\"https://open-design.ai/download\">open-design.ai/download</a> — ele detecta automaticamente os CLIs de agentes instalados. Para rodar a partir do código-fonte (o caminho do Codedigipt):</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abra a URL local que ele imprime — ela resolve uma porta dinâmica, então não fixe nenhuma no código. Uma pegadinha que o Codedigipt aponta por experiência: você precisa do <strong>Node 24</strong>. No Node 22 não iniciava para ele; instale primeiro o Node 24 LTS. O Corepack seleciona a versão fixada do pnpm.</p>\n<h2 id=\"step-2--choose-your-engine\">Passo 2 — Escolha seu motor</h2>\n<p>Este é o passo que importa. Abra as configurações (configurar o modo de execução) e escolha, entre os CLIs que o Open Design detectou na sua máquina, o agente que vai conduzir a geração. Tudo que não estiver instalado aparece desativado.</p>\n<ul>\n<li><strong>Gemini CLI</strong> — a escolha do Codedigipt para a fase de design: bom instinto de design e os créditos do nível gratuito rendem bastante. A geração se apoia nesses créditos.</li>\n<li><strong>Claude Code</strong> — aponte-o para um modelo capaz em design (Sonnet ou Opus) para o resultado de maior fidelidade.</li>\n<li><strong>OpenCode</strong> — vem com modelos padrão competentes (por exemplo, MiniMax, GLM) se você preferir não configurar nada.</li>\n<li><strong>API da Anthropic (BYOK)</strong> — sem CLI? Insira uma chave de API e escolha o modelo diretamente. Isso permite usar resultado com qualidade Claude <strong>sem uma assinatura à parte do Claude Design</strong> — você traz a chave, o Open Design traz a superfície de design.</li>\n</ul>\n<h2 id=\"step-3--generate-then-judge-by-engine\">Passo 3 — Gere e depois julgue pelo motor</h2>\n<p>Crie um projeto, dê um nome, escolha <strong>alta fidelidade</strong> e escreva seu briefing (o Codedigipt constrói uma página de destino para uma API do tipo «auth-as-a-service»). Antes de escrever qualquer coisa, o Open Design retorna um breve <strong>formulário de descoberta</strong> — formato de saída, superfície principal, público, tom visual, direção de marca — para que o agente trave a direção certa em vez de adivinhar. Responda, escolha uma direção visual, e ele constrói.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/generated-prototype.webp\" alt=\"Um protótipo real gerado no Open Design.\">\n<em>Um protótipo real gerado, renderizado na pré-visualização — uma landing page de agência escura e cinematográfica.</em></p>\n<p>O resultado em um modelo rápido (o Codedigipt usa uma prévia do Gemini flash) é uma primeira versão limpa e utilizável em segundos. A ressalva honesta que ele repete: <strong>você obtém um resultado no nível do modelo que escolheu.</strong> Quer um acabamento de calibre Opus? Troque o motor para o Claude no Opus e rode o mesmo briefing de novo — mesma habilidade, mesmo design system, resultado mais afiado.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/plugin-library.webp\" alt=\"A biblioteca de plugins do Open Design, com skills instaláveis.\">\n<em>A biblioteca de plugins: instale skills direto do registro — incluindo skills de design anti-slop.</em></p>\n<p>Quando estiver satisfeito, o menu <strong>Compartilhar</strong> exporta para PDF, PPTX, HTML autônomo ou um ZIP — ou faz o deploy direto na Vercel. Você pode navegar pela biblioteca completa de plugins em <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"tips\">Dicas</h2>\n<ul>\n<li><strong>Case o modelo com a tarefa.</strong> Modelo barato/rápido para rascunhos rápidos e iteração; modelo de ponta para a versão final que vai ao cliente.</li>\n<li><strong>Use um CLI local</strong> para que a geração se apoie em uma assinatura ou créditos gratuitos que você já tem.</li>\n<li><strong>BYOK para qualidade Claude sem um plano do Claude Design</strong> — coloque uma chave da Anthropic nas configurações e selecione o modelo.</li>\n<li><strong>Não culpe a ferramenta por um modelo fraco.</strong> Um bom design system não salva um motor fraco; se o resultado parecer ralo, melhore o modelo antes de reescrever o prompt.</li>\n<li><strong>Responda o formulário de descoberta por completo</strong> — é assim que o motor trava a direção logo na primeira tentativa.</li>\n</ul>\n<h2 id=\"faq\">Perguntas frequentes</h2>\n<p><strong>O modelo que eu escolho muda mesmo tanto o resultado?</strong>\nSim — é a maior alavanca. O Open Design fornece as habilidades e os design systems, mas o juízo de design vem do motor. O mesmo briefing no Opus contra um modelo de prévia rápido produz um acabamento visivelmente diferente.</p>\n<p><strong>Posso ter qualidade de nível Claude sem pagar pelo Claude Design?</strong>\nSim. Aponte o Open Design para o Claude Code, ou coloque uma chave de API da Anthropic nas configurações (BYOK) e selecione o modelo. Você obtém o resultado sem uma assinatura à parte do Claude Design.</p>\n<p><strong>Posso trocar de modelo no meio do projeto?</strong>\nSim — mude o agente/modelo nas configurações e rode de novo. Mesma habilidade e mesmo design system, com outro motor por trás.</p>\n<p><strong>É gratuito?</strong>\nO aplicativo é de código aberto sob a Apache-2.0 e gratuito para rodar localmente. Você só paga pelo modelo/créditos do agente que conectar.</p>\n<hr>\n<p><em>Este guia escrito é baseado no passo a passo prático do Codedigipt. Assista ao vídeo completo acima e <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">inscreva-se no canal do Codedigipt</a> para mais configurações práticas de ferramentas de IA.</em></p>",
  },
  "it": {
    title: "Open Design — Trasforma l’agente che hai già in un motore di design",
    summary: "Una guida pratica alla parte di Open Design che la maggior parte dei tutorial salta: scegliere e sostituire il modello che lo alimenta. Il tuo agente di coding è il motore; il modello a cui lo punti è la manopola della qualità. Installalo, collega Gemini CLI o Claude e impara ad abbinare il modello al compito. Basata sulla guida pratica di Codedigipt.",
    bodyHtml: "<p>Questa guida si concentra sulla parte di Open Design che la maggior parte delle guide sorvola: <strong>il motore</strong>. Open Design di per sé è la superficie di design — la generazione vera è fatta dall’agente di coding e dal modello a cui lo punti, e quella scelta è la leva più grande sulla qualità del risultato. Segue la configurazione che <strong>Codedigipt</strong> usa nella <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">sua guida pratica</a>, riscritta e aggiornata alla versione attuale. Guarda il video qui sopra per la prova dal vivo, oppure prosegui con la versione scritta.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/workspace-home.webp\" alt=\"L'area di lavoro di Open Design: descrivi ciò che vuoi e scegli una modalità.\">\n<em>L'area di lavoro di Open Design: descrivi ciò che vuoi creare, scegli una modalità e il tuo agente fa il resto.</em></p>\n<h2 id=\"what-is-open-design\">Che cos’è Open Design?</h2>\n<p>Open Design è una piattaforma di design open source e local-first che gira <strong>sopra l’agente di coding che usi già</strong>. Non porta con sé un proprio modello — scansiona la tua macchina alla ricerca delle CLI che hai già (Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode e un paio di dozzine in più) e usa quell’agente come motore di design. Così il lavoro gira sull’abbonamento o sui crediti gratuiti che hai già, non su una seconda bolletta di design.</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — clonalo, ospitalo da te, leggine ogni riga.</li>\n<li><strong>Gira in locale</strong> — i tuoi progetti sono cartelle sulla tua stessa macchina.</li>\n<li><strong>Porta il tuo motore</strong> — qualsiasi CLI supportata, o la tua chiave API.</li>\n<li><strong>Un’ampia libreria di design system e skill</strong> integrata, così non parti da una tela bianca.</li>\n<li><strong>Più dei prototipi</strong> — prototipi, presentazioni, generazione di immagini e video.</li>\n</ul>\n<h2 id=\"the-key-idea-the-model-is-the-quality-knob\">L’idea chiave: il modello è la manopola della qualità</h2>\n<p>Ecco il modello mentale a cui arriva Codedigipt, ed è la cosa più utile da interiorizzare: <strong>la qualità del risultato di Open Design segue il modello che scegli.</strong> Open Design fornisce la struttura — skill, design system, il flusso di discovery — ma il vero giudizio di design viene dal motore. Eseguilo su un modello veloce ed economico e ottieni una bozza veloce ed economica; eseguilo su un modello di fascia alta e ottieni un risultato molto più rifinito dallo stesso prompt e design system.</p>\n<p>È un pregio, non un limite. Significa che puoi dosare costo e qualità per ogni progetto e cambiare motore quando vuoi.</p>\n<h2 id=\"step-1--install-open-design\">Passo 1 — Installare Open Design</h2>\n<p>Tre vie d’accesso:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Via</th><th>Ideale per</th><th>Requisiti</th></tr></thead><tbody><tr><td><strong>App desktop</strong></td><td>La maggior parte delle persone — zero configurazione</td><td>Nessuno. Basta scaricare e aprire.</td></tr><tr><td><strong>Eseguire dai sorgenti</strong></td><td>Sviluppatori che vogliono leggere o modificare il codice</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Installare nel tuo agente</strong></td><td>Chi vive nel terminale</td><td>Una CLI di agente di coding già esistente</td></tr></tbody></table>\n<p>La via più rapida è l’<strong>app desktop</strong> da <a href=\"https://open-design.ai/download\">open-design.ai/download</a> — rileva automaticamente le CLI degli agenti installati. Per eseguire dai sorgenti (la via di Codedigipt):</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Apri l’URL locale che stampa — risolve una porta dinamica, quindi non fissarne nessuna nel codice. Un inciampo che Codedigipt segnala per esperienza: ti serve <strong>Node 24</strong>. Su Node 22 non gli partiva; installa prima Node 24 LTS. Corepack seleziona la versione fissata di pnpm.</p>\n<h2 id=\"step-2--choose-your-engine\">Passo 2 — Scegli il tuo motore</h2>\n<p>Questo è il passo che conta. Apri le impostazioni (configura la modalità di esecuzione) e scegli, tra le CLI che Open Design ha rilevato sulla tua macchina, l’agente che guiderà la generazione. Tutto ciò che non è installato appare disabilitato.</p>\n<ul>\n<li><strong>Gemini CLI</strong> — la scelta di Codedigipt per la fase di design: forte istinto di design, e i crediti del piano gratuito rendono parecchio. La generazione viaggia su quei crediti.</li>\n<li><strong>Claude Code</strong> — puntalo su un modello capace nel design (Sonnet o Opus) per il risultato di massima fedeltà.</li>\n<li><strong>OpenCode</strong> — arriva con modelli predefiniti capaci (ad es. MiniMax, GLM) se preferisci non configurare nulla.</li>\n<li><strong>API Anthropic (BYOK)</strong> — niente CLI? Inserisci una chiave API e scegli il modello direttamente. Questo ti permette di usare un risultato di qualità Claude <strong>senza un abbonamento a parte a Claude Design</strong> — tu porti la chiave, Open Design porta la superficie di design.</li>\n</ul>\n<h2 id=\"step-3--generate-then-judge-by-engine\">Passo 3 — Genera, poi giudica in base al motore</h2>\n<p>Crea un progetto, dagli un nome, scegli l’<strong>alta fedeltà</strong> e scrivi il tuo brief (Codedigipt costruisce una landing page per un’API «auth-as-a-service»). Prima di scrivere qualsiasi cosa, Open Design restituisce un breve <strong>modulo di discovery</strong> — formato di output, superficie principale, pubblico, tono visivo, direzione di marca — così l’agente blocca la direzione giusta invece di tirare a indovinare. Rispondi, scegli una direzione visiva, e costruisce.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/generated-prototype.webp\" alt=\"Un vero prototipo generato in Open Design.\">\n<em>Un vero prototipo generato, mostrato nell'anteprima: una landing page d'agenzia scura e cinematografica.</em></p>\n<p>Il risultato su un modello veloce (Codedigipt usa un’anteprima Gemini flash) è una prima stesura pulita e utilizzabile in pochi secondi. L’onesta avvertenza che ripete: <strong>ottieni un risultato al livello del modello che hai scelto.</strong> Vuoi una rifinitura da Opus? Cambia il motore su Claude con Opus e rilancia lo stesso brief — stessa skill, stesso design system, risultato più nitido.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/plugin-library.webp\" alt=\"La libreria di plugin di Open Design, con skill installabili.\">\n<em>La libreria di plugin: installa skill direttamente dal registro, incluse skill di design anti-slop.</em></p>\n<p>Quando sei soddisfatto, il menu <strong>Condividi</strong> esporta in PDF, PPTX, HTML autonomo o uno ZIP — oppure fa il deploy direttamente su Vercel. Puoi sfogliare l’intera libreria di plugin su <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"tips\">Suggerimenti</h2>\n<ul>\n<li><strong>Abbina il modello al compito.</strong> Modello economico/veloce per bozze rapide e iterazione; modello di fascia alta per la passata finale destinata al cliente.</li>\n<li><strong>Usa una CLI locale</strong> così la generazione viaggia su un abbonamento o su crediti gratuiti che hai già.</li>\n<li><strong>BYOK per la qualità Claude senza un piano Claude Design</strong> — inserisci una chiave Anthropic nelle impostazioni e seleziona il modello.</li>\n<li><strong>Non incolpare lo strumento per un modello debole.</strong> Un buon design system non può salvare un motore debole; se il risultato sembra povero, aggiorna il modello prima di riscrivere il prompt.</li>\n<li><strong>Compila per intero il modulo di discovery</strong> — è così che il motore blocca la direzione al primo tentativo.</li>\n</ul>\n<h2 id=\"faq\">Domande frequenti</h2>\n<p><strong>Il modello che scelgo cambia davvero così tanto il risultato?</strong>\nSì — è la leva più grande. Open Design fornisce le skill e i design system, ma il giudizio di design viene dal motore. Lo stesso brief su Opus rispetto a un modello d’anteprima veloce produce una rifinitura nettamente diversa.</p>\n<p><strong>Posso avere una qualità di livello Claude senza pagare Claude Design?</strong>\nSì. Punta Open Design su Claude Code, oppure inserisci una chiave API Anthropic nelle impostazioni (BYOK) e seleziona il modello. Ottieni il risultato senza un abbonamento a parte a Claude Design.</p>\n<p><strong>Posso cambiare modello a metà progetto?</strong>\nSì — cambia l’agente/modello nelle impostazioni e rilancia. Stessa skill e stesso design system, ma un motore diverso dietro.</p>\n<p><strong>È gratuito?</strong>\nL’app è open source sotto Apache-2.0 e gratuita da eseguire in locale. Paghi solo il modello/i crediti dell’agente che colleghi.</p>\n<hr>\n<p><em>Questa guida scritta si basa sulla guida pratica di Codedigipt. Guarda il video completo qui sopra e <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">iscriviti a Codedigipt</a> per altre configurazioni pratiche di strumenti di IA.</em></p>",
  },
  "tr": {
    title: "Open Design — Elinizdeki ajanı bir tasarım motoruna dönüştürün",
    summary: "Çoğu eğitimin atladığı Open Design kısmına ilişkin pratik bir rehber: arkasındaki modeli seçmek ve değiştirmek. Kodlama ajanınız motordur; onu yönlendirdiğiniz model ise kalite düğmesidir. Kurun, Gemini CLI veya Claude’u bağlayın ve modeli işe göre eşleştirmeyi öğrenin. Codedigipt’in uygulamalı anlatımına dayanır.",
    bodyHtml: "<p>Bu rehber, çoğu anlatımın üstünkörü geçtiği kısma odaklanıyor: <strong>motor</strong>. Open Design’ın kendisi tasarım yüzeyidir — asıl üretimi, yönlendirdiğiniz kodlama ajanı ve model yapar ve bu seçim, çıktı kalitesindeki en büyük kaldıraçtır. <strong>Codedigipt</strong>’in <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">uygulamalı anlatımında</a> kullandığı kurulumu izler; yeniden yazılmış ve güncel sürüme uyarlanmıştır. Canlı çalışma için yukarıdaki videoyu izleyin ya da yazılı sürümü okumaya devam edin.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/workspace-home.webp\" alt=\"Open Design çalışma alanı — ne istediğinizi anlatın ve bir mod seçin.\">\n<em>Open Design çalışma alanı: oluşturmak istediğinizi anlatın, bir mod seçin, gerisini ajanınız halletsin.</em></p>\n<h2 id=\"what-is-open-design\">Open Design nedir?</h2>\n<p>Open Design, <strong>zaten kullandığınız kodlama ajanının üzerinde çalışan</strong>, açık kaynaklı ve önce-yerel bir tasarım platformudur. Kendi modelini getirmez — makinenizde halihazırda bulunan CLI’ları (Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode ve birkaç düzine daha) tarar ve o ajanı tasarım motoru olarak kullanır. Böylece iş, ikinci bir tasarım faturası yerine zaten sahip olduğunuz abonelik veya ücretsiz kredilerle yürür.</p>\n<ul>\n<li><strong>Açık kaynak, Apache-2.0</strong> — klonlayın, kendiniz barındırın, her satırı okuyun.</li>\n<li><strong>Yerelde çalışır</strong> — projeleriniz kendi makinenizdeki klasörlerdir.</li>\n<li><strong>Kendi motorunuzu getirin</strong> — desteklenen herhangi bir CLI ya da kendi API anahtarınız.</li>\n<li><strong>Yerleşik, geniş bir tasarım sistemleri ve beceriler kütüphanesi</strong> sayesinde boş bir tuvalden başlamazsınız.</li>\n<li><strong>Prototipten fazlası</strong> — prototipler, sunum desteleri, görsel üretimi ve video.</li>\n</ul>\n<h2 id=\"the-key-idea-the-model-is-the-quality-knob\">Temel fikir: model, kalite düğmesidir</h2>\n<p>İşte Codedigipt’in vardığı zihinsel model ve içselleştirilmesi en yararlı şey: <strong>Open Design’ın çıktı kalitesi seçtiğiniz modeli izler.</strong> Open Design yapıyı sağlar — beceriler, tasarım sistemleri, keşif akışı — ama asıl tasarım yargısı motordan gelir. Hızlı ve ucuz bir modelde çalıştırın, hızlı ve ucuz bir taslak alırsınız; üst düzey bir modelde çalıştırın, aynı istem ve tasarım sisteminden çok daha cilalı bir sonuç alırsınız.</p>\n<p>Bu bir kısıt değil, bir özelliktir. Yani her proje için maliyeti kaliteyle dengeleyebilir ve motoru dilediğiniz zaman değiştirebilirsiniz.</p>\n<h2 id=\"step-1--install-open-design\">1. Adım — Open Design’ı kurun</h2>\n<p>Üç giriş yolu:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Yol</th><th>En uygunu</th><th>Gereksinimler</th></tr></thead><tbody><tr><td><strong>Masaüstü uygulaması</strong></td><td>Çoğu kişi — sıfır yapılandırma</td><td>Yok. Sadece indirip açın.</td></tr><tr><td><strong>Kaynaktan çalıştırma</strong></td><td>Kodu okumak veya değiştirmek isteyen geliştiriciler</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Ajanınıza kurma</strong></td><td>Terminalde yaşayanlar</td><td>Mevcut bir kodlama ajanı CLI’ı</td></tr></tbody></table>\n<p>En hızlı yol, <a href=\"https://open-design.ai/download\">open-design.ai/download</a> adresinden <strong>masaüstü uygulamasıdır</strong> — kurulu ajan CLI’larınızı otomatik algılar. Kaynaktan çalıştırmak için (Codedigipt’in yolu):</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Yazdırdığı yerel URL’yi açın — dinamik bir bağlantı noktasını çözer, bu yüzden hiçbirini koda sabitlemeyin. Codedigipt’in deneyimle işaret ettiği bir tuzak: <strong>Node 24</strong> gerekiyor. Node 22’de onda başlamadı; önce Node 24 LTS’yi kurun. Corepack, sabitlenmiş pnpm sürümünü seçer.</p>\n<h2 id=\"step-2--choose-your-engine\">2. Adım — Motorunuzu seçin</h2>\n<p>İşte asıl önemli adım. Ayarları açın (yürütme modunu yapılandırın) ve Open Design’ın makinenizde algıladığı CLI’lar arasından üretimi sürecek ajanı seçin. Kurulu olmayan her şey devre dışı görünür.</p>\n<ul>\n<li><strong>Gemini CLI</strong> — Codedigipt’in tasarım aşaması için tercihi: güçlü tasarım sezgisi ve ücretsiz katman kredileri uzun süre yeter. Üretim bu kredilerle yürür.</li>\n<li><strong>Claude Code</strong> — en yüksek bağlılıkta çıktı için onu tasarıma yatkın bir modele (Sonnet veya Opus) yönlendirin.</li>\n<li><strong>OpenCode</strong> — hiçbir şeyi yapılandırmak istemiyorsanız, yetkin varsayılan modellerle (ör. MiniMax, GLM) gelir.</li>\n<li><strong>Anthropic API (BYOK)</strong> — CLI yok mu? Bir API anahtarı girin ve modeli doğrudan seçin. Bu, <strong>ayrı bir Claude Design aboneliği olmadan</strong> Claude kalitesinde çıktı kullanmanızı sağlar — anahtarı siz getirirsiniz, tasarım yüzeyini Open Design.</li>\n</ul>\n<h2 id=\"step-3--generate-then-judge-by-engine\">3. Adım — Üretin, sonra motora göre değerlendirin</h2>\n<p>Bir proje oluşturun, ad verin, <strong>yüksek bağlılık</strong> seçin ve brifinginizi yazın (Codedigipt bir «auth-as-a-service» API’si için açılış sayfası kuruyor). Herhangi bir şey yazmadan önce Open Design kısa bir <strong>keşif formu</strong> döndürür — çıktı biçimi, birincil yüzey, hedef kitle, görsel ton, marka yönü — böylece ajan tahmin yürütmek yerine doğru yönü kilitler. Yanıtlayın, bir görsel yön seçin, o da kurar.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/generated-prototype.webp\" alt=\"Open Design'da üretilen gerçek bir prototip.\">\n<em>Önizlemede gösterilen gerçek bir üretilmiş prototip — koyu, sinematik bir ajans açılış sayfası.</em></p>\n<p>Hızlı bir modelde sonuç (Codedigipt bir Gemini flash önizlemesi kullanıyor), saniyeler içinde temiz, kullanılabilir bir ilk geçiştir. Onun tekrarladığı dürüst uyarı: <strong>çıktıyı, seçtiğiniz modelin düzeyinde alırsınız.</strong> Opus ayarında bir cila mı istiyorsunuz? Motoru Opus üzerinde Claude’a geçirin ve aynı brifingi yeniden çalıştırın — aynı beceri, aynı tasarım sistemi, daha keskin sonuç.</p>\n<p><img src=\"/tutorials/open-design-design-engine-codedigipt/plugin-library.webp\" alt=\"Kurulabilir yeteneklerle birlikte Open Design eklenti kütüphanesi.\">\n<em>Eklenti kütüphanesi: yetenekleri doğrudan kayıt defterinden kurun — anti-slop tasarım yetenekleri dahil.</em></p>\n<p>Memnun kaldığınızda <strong>Paylaş</strong> menüsü PDF, PPTX, bağımsız HTML veya bir ZIP olarak dışa aktarır — ya da doğrudan Vercel’e dağıtır. Eksiksiz eklenti kütüphanesine <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> adresinden göz atabilirsiniz.</p>\n<h2 id=\"tips\">İpuçları</h2>\n<ul>\n<li><strong>Modeli işe göre eşleştirin.</strong> Hızlı taslaklar ve yineleme için ucuz/hızlı model; müşteriye gidecek son geçiş için üst düzey model.</li>\n<li><strong>Yerel bir CLI kullanın</strong> ki üretim, zaten sahip olduğunuz bir abonelik veya ücretsiz kredilerle yürüsün.</li>\n<li><strong>Claude Design planı olmadan Claude kalitesi için BYOK</strong> — ayarlara bir Anthropic anahtarı bırakın ve modeli seçin.</li>\n<li><strong>Zayıf bir model için aracı suçlamayın.</strong> İyi bir tasarım sistemi zayıf bir motoru kurtaramaz; çıktı cılız görünüyorsa, istemi yeniden yazmadan önce modeli yükseltin.</li>\n<li><strong>Keşif formunu eksiksiz yanıtlayın</strong> — motor yönü ilk denemede böyle kilitler.</li>\n</ul>\n<h2 id=\"faq\">SSS</h2>\n<p><strong>Seçtiğim model çıktıyı gerçekten bu kadar değiştiriyor mu?</strong>\nEvet — en büyük kaldıraç bu. Open Design becerileri ve tasarım sistemlerini sağlar, ama tasarım yargısı motordan gelir. Aynı brifing, Opus ile hızlı bir önizleme modelinde gözle görülür biçimde farklı bir cila üretir.</p>\n<p><strong>Claude Design için ödeme yapmadan Claude düzeyinde kalite alabilir miyim?</strong>\nEvet. Open Design’ı Claude Code’a yönlendirin ya da ayarlara bir Anthropic API anahtarı bırakın (BYOK) ve modeli seçin. Ayrı bir Claude Design aboneliği olmadan çıktıyı alırsınız.</p>\n<p><strong>Proje ortasında model değiştirebilir miyim?</strong>\nEvet — ayarlardan ajanı/modeli değiştirin ve yeniden çalıştırın. Aynı beceri ve aynı tasarım sistemi, arkasında farklı bir motor.</p>\n<p><strong>Ücretsiz mi?</strong>\nUygulama Apache-2.0 altında açık kaynaktır ve yerelde çalıştırması ücretsizdir. Yalnızca bağladığınız ajanın modeli/kredileri için ödersiniz.</p>\n<hr>\n<p><em>Bu yazılı rehber, Codedigipt’in uygulamalı anlatımına dayanır. Yukarıdaki tam videoyu izleyin ve daha fazla pratik yapay zekâ aracı kurulumu için <a href=\"https://www.youtube.com/watch?v=Z9_ruLqDJkM\">Codedigipt’e abone olun</a>.</em></p>",
  },
};
